def is_prime_power(n):
    """Check if n = p^k for prime p, k >= 1."""
    if n < 2: return False
    for p in range(2, int(n**0.5) + 1):
        if is_prime(p):
            pk = p
            while pk < n:
                pk *= p
            if pk == n:
                return p
    return n if is_prime(n) else None

