        return []

    if (N - 1) % 4 == 0:  # N ≡ 1 mod 4: QR
        conn = set()
        for x in range(1, N):
            conn.add((x * x) % N)
    else:  # N ≡ 3 mod 4: QNR
        qr = set()
        for x in range(1, N):
            qr.add((x * x) % N)
