"""Cayley graph on Z/p × Z/q using QR connection sets."""

def construct(N):
    # Target composite primes: p*q where p,q ≡ 1 mod 4
    candidates = {
        25: (5, 5),
    }
    if N not in candidates:
        return []

    p, q = candidates[N]

    # QR in Z/p and Z/q
    qr_p = {pow(i, (p-1)//2, p) for i in range(1, p)}
    qr_q = {pow(i, (q-1)//2, q) for i in range(1, q)}

    edges = []
    for i in range(p):
        for j in range(q):
            u = i * q + j
            # Connect to (i±a, j), (i, j±b) for a ∈ QR_p, b ∈ QR_q
            for a in qr_p:
                for di in [a, p-a]:
                    v_i = (i + di) % p
                    v = v_i * q + j
                    if u < v:
                        edges.append((u, v))
            for b in qr_q:
                for dj in [b, q-b]:
                    v_j = (j + dj) % q
                    v = i * q + v_j
                    if u < v:
                        edges.append((u, v))

    return list(set(edges))

