    if N == 8:
        e = []
        for i in range(8):
            for k in [1, 2]:
                j = (i + k) % 8
                a, b = (i, j) if i < j else (j, i)
                e.append((a, b))
        return e
    elif N == 17 or N == 19:
        exp = (N - 1) // (2 if N == 17 else 3)
        e = []
        for i in range(N):
            for j in range(i + 1, N):
                if pow((j - i) % N, exp, N) == 1:
                    e.append((i, j))
        return e
    return []

# Family: hamming
"""Enhanced Hamming: connect vertices at distance 1 or k-1 in hypercube."""

def construct(N):
    if N & (N - 1) == 0 and N > 1:
        k = (N - 1).bit_length()
        if 2 ** k != N:
            return []
    else:
        return []

    edges = []
    for i in range(N):
        for j in range(i + 1, N):
            hd = bin(i ^ j).count('1')
            if hd == 1 or hd == k - 1:
                edges.append((i, j))

    return edges

# Family: peisert
"""Peisert-like construction: QR union with special element for primes ≡ 5 mod 8."""

def construct(N):
    if N % 8 != 5:
        return []
    if N < 2 or any(N % i == 0 for i in range(2, int(N**0.5) + 1)):
        return []

    qr = set((i*i) % N for i in range(N))
    special = (-(N-1)//4) % N
    edges = []

    for i in range(N):
        for j in range(i+1, N):
            diff = (j - i) % N
            if diff in qr or diff == special:
                edges.append((i, j))

    return edges

# Family: product
"""Cartesian product of two cycles C_m □ C_n. Bipartite => K4-free."""

def construct(N):
    import math
    for m in range(2, int(math.sqrt(N)) + 2):
        if N % m == 0:
            n = N // m
            if n >= 2:
                edges = []
                for i in range(m):
                    for j in range(n):
                        u = i * n + j
                        # Edge along C_m
                        v = ((i + 1) % m) * n + j
                        if u < v:
                            edges.append((u, v))
                        # Edge along C_n
                        v = i * n + ((j + 1) % n)
                        if u < v:
                            edges.append((u, v))
                return edges
    return []

# Family: blowup
"""Blowup of C_5: replace each vertex with independent set, blow up edges."""

def construct(N):
    if N % 5 != 0:
        return []

    k = N // 5
    edges = []

    # C_5 edges: 0-1, 1-2, 2-3, 3-4, 4-0
    for u_base, v_base in [(0, 1), (1, 2), (2, 3), (3, 4), (4, 0)]:
        for i in range(k):
            for j in range(k):
                u = u_base * k + i
                v = v_base * k + j
                if u < v:
                    edges.append((u, v))

    return edges

# Family: polarity
"""Polarity graph of PG(2,3): orthogonality in finite projective plane."""

def construct(N):
    if N != 13:
        return []

    # PG(2,3) has 13 points and 13 lines
    # Points: [0, 13), representing 1-d subspaces of F_3^3
    # Use standard coordinates mod 3

    from itertools import combinations

    points = []
    for x in range(3):
        for y in range(3):
            for z in range(3):
                if (x, y, z) != (0, 0, 0):
                    points.append((x, y, z))

    # Normalize to canonical form (divide by first non-zero)
    def normalize(p):
        for c in p:
            if c != 0:
                inv = pow(c, 1, 3)  # Multiplicative inverse mod 3
                return tuple((c * inv) % 3 for c in p)
        return p

    points = list(set(normalize(p) for p in points))[:13]

    edges = []

    # Two points are orthogonal if their dot product is 0 mod 3
    for i, p1 in enumerate(points):
        for j, p2 in enumerate(points):
            if i < j:
                dot = sum(p1[k] * p2[k] for k in range(3)) % 3
                if dot == 0:
                    edges.append((i, j))

    return edges

# Family: latin_square
"""Latin rectangle graph: cells (i,j,k) with N=n^2, connected if share row or column."""

def construct(N):
    import math

    n = int(math.sqrt(N) + 0.5)
    if n * n != N or n < 3:
        return []

    # Vertices: (i,j) pairs for i,j in [0,n)
    edges = []

    for i1 in range(n):
        for j1 in range(n):
            for i2 in range(n):
                for j2 in range(n):
                    v1 = i1 * n + j1
                    v2 = i2 * n + j2
                    if v1 < v2:
                        # Connected if same row XOR same column (but not both, not neither)
                        same_row = (i1 == i2)
                        same_col = (j1 == j2)
                        if same_row != same_col:
                            edges.append((v1, v2))

    return edges
